#include <stdio.h>
#include <stdlib.h>
#define MAX 400005
typedef struct Edge {
    int u, v;
} Edge;
int compare(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return e1->u - e2->u;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, si, p;
        scanf("%d %d %d", &N, &si, &p);
        Edge edges[N-1];
        for (int i = 0; i < N-1; i++) {
            scanf("%d %d", &edges[i].u, &edges[i].v);
        }
        qsort(edges, N-1, sizeof(Edge), compare);
        int M;
        scanf("%d", &M);
        int robbers[M][4];
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d %d", &robbers[i][0], &robbers[i][1], &robbers[i][2], &robbers[i][3]);
        }
        // Greedy approach
        for (int i = 0; i < M; i++) {
            if (p > robbers[i][2]) {
                p += robbers[i][3];
            }
        }
        printf("%d\n", p);
    }
    return 0;
}

