import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int si = sc.nextInt();
            int p = sc.nextInt();
            int[][] edges = new int[N-1][2];
            for (int i = 0; i < N-1; i++) {
                edges[i][0] = sc.nextInt();
                edges[i][1] = sc.nextInt();
            }
            Arrays.sort(edges, (a, b) -> a[0] - b[0]);
            int M = sc.nextInt();
            int[][] robbers = new int[M][4];
            for (int i = 0; i < M; i++) {
                robbers[i][0] = sc.nextInt();
                robbers[i][1] = sc.nextInt();
                robbers[i][2] = sc.nextInt();
                robbers[i][3] = sc.nextInt();
            }
            // Greedy approach
            for (int i = 0; i < M; i++) {
                if (p > robbers[i][2]) {
                    p += robbers[i][3];
                }
            }
            System.out.println(p);
        }
    }
}

